import Foundation
import CoreLocation

struct POI: Identifiable, Codable, Hashable {
    let id: String
    var name: String
    var category: POICategory
    var coordinate: CLLocationCoordinate2DCodable
    var rating: Double
    var avgPrice: Double
    var imageUrl: String?
    var openingHours: String?
    var queueTime: Int? // 预估排队时间（分钟）
    var description: String?
    var phoneNumber: String?

    enum POICategory: String, Codable, CaseIterable {
        case restaurant = "restaurant"
        case cafe = "cafe"
        case cinema = "cinema"
        case museum = "museum"
        case park = "park"
        case shopping = "shopping"
        case entertainment = "entertainment"
        case scenic = "scenic"
        case other = "other"

        var displayName: String {
            switch self {
            case .restaurant: return "美食"
            case .cafe: return "咖啡"
            case .cinema: return "电影"
            case .museum: return "博物馆"
            case .park: return "公园"
            case .shopping: return "购物"
            case .entertainment: return "娱乐"
            case .scenic: return "景点"
            case .other: return "其他"
            }
        }

        var iconName: String {
            switch self {
            case .restaurant: return "fork.knife"
            case .cafe: return "cup.and.saucer.fill"
            case .cinema: return "film.fill"
            case .museum: return "building.columns.fill"
            case .park: return "leaf.fill"
            case .shopping: return "bag.fill"
            case .entertainment: return "gamecontroller.fill"
            case .scenic: return "camera.fill"
            case .other: return "mappin"
            }
        }
    }

    func hash(into hasher: inout Hasher) {
        hasher.combine(id)
    }

    static func == (lhs: POI, rhs: POI) -> Bool {
        lhs.id == rhs.id
    }
}

// Codable wrapper for CLLocationCoordinate2D
struct CLLocationCoordinate2DCodable: Codable, Hashable {
    var latitude: Double
    var longitude: Double

    init(latitude: Double, longitude: Double) {
        self.latitude = latitude
        self.longitude = longitude
    }

    init(from coordinate: CLLocationCoordinate2D) {
        self.latitude = coordinate.latitude
        self.longitude = coordinate.longitude
    }

    var clLocationCoordinate2D: CLLocationCoordinate2D {
        CLLocationCoordinate2D(latitude: latitude, longitude: longitude)
    }
}

import Foundation

struct RoutePlan: Identifiable, Codable {
    let id: String
    var title: String
    var totalDuration: TimeInterval // 秒
    var totalCost: Double
    var pois: [POI]
    var segments: [RouteSegment]
    var explanation: String
    var tag: RouteTag

    enum RouteTag: String, Codable {
        case experience = "体验优先"
        case fastest = "最省时"
        case cheapest = "最省钱"

        var color: String {
            switch self {
            case .experience: return "purple"
            case .fastest: return "blue"
            case .cheapest: return "green"
            }
        }
    }

    var formattedDuration: String {
        let hours = Int(totalDuration) / 3600
        let minutes = (Int(totalDuration) % 3600) / 60
        if hours > 0 {
            return "\(hours)小时\(minutes)分钟"
        }
        return "\(minutes)分钟"
    }

    var formattedCost: String {
        return "¥\(Int(totalCost))"
    }
}

struct RouteSegment: Identifiable, Codable {
    let id: String
    var fromPOI: POI
    var toPOI: POI
    var transportMode: TransportMode
    var duration: TimeInterval
    var distance: Double
    var polylinePoints: [CLLocationCoordinate2DCodable]?

    enum TransportMode: String, Codable {
        case walking = "walking"
        case driving = "driving"
        case transit = "transit"

        var displayName: String {
            switch self {
            case .walking: return "步行"
            case .driving: return "驾车"
            case .transit: return "公交"
            }
        }

        var iconName: String {
            switch self {
            case .walking: return "figure.walk"
            case .driving: return "car.fill"
            case .transit: return "bus.fill"
            }
        }
    }
}

import Foundation
import SwiftUI

struct Participant: Identifiable, Codable, Hashable {
    let id: String
    var name: String
    var avatarColor: AvatarColor
    var startCoordinate: CLLocationCoordinate2DCodable
    var currentRouteSegmentId: String?

    enum AvatarColor: String, Codable, CaseIterable {
        case blue = "blue"
        case pink = "pink"
        case green = "green"
        case orange = "orange"
        case purple = "purple"
        case teal = "teal"

        var color: Color {
            switch self {
            case .blue: return .blue
            case .pink: return .pink
            case .green: return .green
            case .orange: return .orange
            case .purple: return .purple
            case .teal: return .teal
            }
        }

        var displayName: String {
            switch self {
            case .blue: return "蓝色"
            case .pink: return "粉色"
            case .green: return "绿色"
            case .orange: return "橙色"
            case .purple: return "紫色"
            case .teal: return "青色"
            }
        }
    }

    func hash(into hasher: inout Hasher) {
        hasher.combine(id)
    }

    static func == (lhs: Participant, rhs: Participant) -> Bool {
        lhs.id == rhs.id
    }
}

import Foundation
import SwiftUI

struct SessionState: Codable {
    var sessionId: String
    var plans: [RoutePlan]
    var currentPlanIndex: Int
    var participants: [Participant]
    var adjustmentHistory: [AdjustmentSnapshot]

    var currentPlan: RoutePlan? {
        guard plans.indices.contains(currentPlanIndex) else { return nil }
        return plans[currentPlanIndex]
    }

    var canUndo: Bool {
        adjustmentHistory.contains(where: { $0.type == .adjust })
    }

    var canRedo: Bool {
        adjustmentHistory.contains(where: { $0.type == .undo })
    }

    init(sessionId: String, plans: [RoutePlan], participants: [Participant]) {
        self.sessionId = sessionId
        self.plans = plans
        self.currentPlanIndex = 0
        self.participants = participants
        self.adjustmentHistory = []
    }
}

struct AdjustmentSnapshot: Codable {
    let id: String
    let type: AdjustmentType
    let plans: [RoutePlan]
    let timestamp: Date

    enum AdjustmentType: String, Codable {
        case adjust = "adjust"
        case undo = "undo"
        case redo = "redo"
    }
}

