import Foundation
import CoreLocation

actor RouteNetworkService {
    private let baseURL = "http://localhost:8080"
    private let session: URLSession
    private let maxRetries = 3
    private let retryDelay: TimeInterval = 1.0

    init() {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.waitsForConnectivity = true
        self.session = URLSession(configuration: config)
    }

    // MARK: - 路线规划
    func planRoute(
        query: String,
        sessionId: String? = nil,
        participants: [Participant]
    ) async throws -> [RoutePlan] {
        let body = PlanRouteRequest(
            query: query,
            sessionId: sessionId,
            participants: participants.map { participant in
                ParticipantRequest(
                    userId: participant.id,
                    start: CoordinateRequest(
                        lat: participant.startCoordinate.latitude,
                        lng: participant.startCoordinate.longitude
                    )
                )
            }
        )

        return try await retryableRequest(
            endpoint: "/api/route/plan",
            body: body,
            mapResponse: { (response: RoutePlanResponse) in response.plans }
        )
    }

    // MARK: - 路线调整
    func adjustRoute(sessionId: String, adjustment: String) async throws -> [RoutePlan] {
        let body = AdjustRouteRequest(
            sessionId: sessionId,
            adjustment: adjustment
        )

        return try await retryableRequest(
            endpoint: "/api/route/adjust",
            body: body,
            mapResponse: { (response: RoutePlanResponse) in response.plans }
        )
    }

    // MARK: - 获取对比方案
    func getCompare(sessionId: String) async throws -> [RoutePlan] {
        let url = URL(string: "\(baseURL)/api/route/compare/\(sessionId)")!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Accept")

        return try await retryableRequest(
            urlRequest: request,
            mapResponse: { (response: RoutePlanResponse) in response.plans }
        )
    }

    // MARK: - 通用请求方法
    private func performRequest<T: Decodable>(
        endpoint: String,
        body: Encodable
    ) async throws -> T {
        let url = URL(string: "\(baseURL)\(endpoint)")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.httpBody = try JSONEncoder().encode(AnyEncodable(body))

        let (data, response) = try await session.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.invalidResponse
        }

        guard (200...299).contains(httpResponse.statusCode) else {
            throw NetworkError.httpError(statusCode: httpResponse.statusCode)
        }

        return try JSONDecoder().decode(T.self, from: data)
    }

    private func retryableRequest<Body: Encodable, Response: Decodable>(
        endpoint: String,
        body: Body,
        mapResponse: @escaping (Response) -> [RoutePlan]
    ) async throws -> [RoutePlan] {
        var lastError: Error = NetworkError.unknown

        for attempt in 0...maxRetries {
            do {
                let response: Response = try await performRequest(endpoint: endpoint, body: body)
                return mapResponse(response)
            } catch {
                lastError = error
                if attempt < maxRetries {
                    let delay = retryDelay * pow(2.0, Double(attempt))
                    try await Task.sleep(nanoseconds: UInt64(delay * 1_000_000_000))
                }
            }
        }

        throw lastError
    }

    private func retryableRequest<Response: Decodable>(
        urlRequest: URLRequest,
        mapResponse: @escaping (Response) -> [RoutePlan]
    ) async throws -> [RoutePlan] {
        var lastError: Error = NetworkError.unknown

        for attempt in 0...maxRetries {
            do {
                let (data, response) = try await session.data(for: urlRequest)
                guard let httpResponse = response as? HTTPURLResponse else {
                    throw NetworkError.invalidResponse
                }
                guard (200...299).contains(httpResponse.statusCode) else {
                    throw NetworkError.httpError(statusCode: httpResponse.statusCode)
                }
                let decoded: Response = try JSONDecoder().decode(Response.self, from: data)
                return mapResponse(decoded)
            } catch {
                lastError = error
                if attempt < maxRetries {
                    let delay = retryDelay * pow(2.0, Double(attempt))
                    try await Task.sleep(nanoseconds: UInt64(delay * 1_000_000_000))
                }
            }
        }

        throw lastError
    }
}

// MARK: - 请求/响应模型
struct PlanRouteRequest: Encodable {
    let query: String
    let sessionId: String?
    let participants: [ParticipantRequest]
}

struct ParticipantRequest: Encodable {
    let userId: String
    let start: CoordinateRequest
}

struct CoordinateRequest: Encodable {
    let lat: Double
    let lng: Double
}

struct AdjustRouteRequest: Encodable {
    let sessionId: String
    let adjustment: String
}

struct RoutePlanResponse: Decodable {
    let plans: [RoutePlan]
}

// MARK: - 错误类型
enum NetworkError: LocalizedError {
    case invalidResponse
    case httpError(statusCode: Int)
    case decodingError
    case unknown

    var errorDescription: String? {
        switch self {
        case .invalidResponse:
            return "服务器响应无效"
        case .httpError(let statusCode):
            return "服务器错误 (\(statusCode))"
        case .decodingError:
            return "数据解析失败"
        case .unknown:
            return "未知网络错误"
        }
    }
}

// MARK: - Helper for type-erased encoding
struct AnyEncodable: Encodable {
    private let _encode: (Encoder) throws -> Void

    init(_ wrapped: Encodable) {
        _encode = { encoder in
            try wrapped.encode(to: encoder)
        }
    }

    func encode(to encoder: Encoder) throws {
        try _encode(encoder)
    }
}

import Foundation
import CoreLocation
import MapKit
import Combine

actor LocationService: NSObject, CLLocationManagerDelegate {
    static let shared = LocationService()

    private let manager = CLLocationManager()
    private var continuation: CheckedContinuation<CLLocation, Error>?

    private override init() {
        super.init()
        manager.delegate = self
        manager.desiredAccuracy = kCLLocationAccuracyBest
    }

    nonisolated func requestCurrentLocation() async throws -> CLLocation {
        return try await withCheckedThrowingContinuation { continuation in
            Task { [weak self] in
                guard let self = self else {
                    continuation.resume(throwing: LocationError.serviceUnavailable)
                    return
                }

                let status = self.manager.authorizationStatus
                guard status == .authorizedWhenInUse || status == .authorizedAlways else {
                    continuation.resume(throwing: LocationError.notAuthorized)
                    return
                }

                await self.setContinuation(continuation)
                self.manager.startUpdatingLocation()
            }
        }
    }

    nonisolated func requestAuthorization() {
        manager.requestWhenInUseAuthorization()
    }

    // MARK: - CLLocationManagerDelegate
    nonisolated func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let location = locations.last else { return }
        manager.stopUpdatingLocation()
        Task { await self.resumeContinuation(with: location) }
    }

    nonisolated func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        manager.stopUpdatingLocation()
        Task { await self.resumeContinuation(throwing: error) }
    }

    nonisolated func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
        // 授权状态变化处理
    }

    private func setContinuation(_ cont: CheckedContinuation<CLLocation, Error>) {
        continuation = cont
    }

    private func resumeContinuation(with location: CLLocation) {
        continuation?.resume(returning: location)
        continuation = nil
    }

    private func resumeContinuation(throwing error: Error) {
        continuation?.resume(throwing: error)
        continuation = nil
    }
}

enum LocationError: LocalizedError {
    case notAuthorized
    case serviceUnavailable
    case noLocation

    var errorDescription: String? {
        switch self {
        case .notAuthorized: return "位置权限未开启"
        case .serviceUnavailable: return "定位服务不可用"
        case .noLocation: return "无法获取当前位置"
        }
    }
}

