                .rotationEffect(.degrees(rotation))
                .scaleEffect(scale)

            // 中层环
            Circle()
                .stroke(
                    AngularGradient(
                        colors: [
                            .blue.opacity(0.5),
                            .purple.opacity(0.3),
                            .blue.opacity(0.5)
                        ],
                        center: .center
                    ),
                    lineWidth: 3
                )
                .frame(width: 60, height: 60)
                .rotationEffect(.degrees(-rotation * 1.3))

            // 内层环
