    @State private var startAngle: Double = 0

    var body: some View {
        TimelineView(.animation(minimumInterval: 0.016)) { timeline in
            let angle = startAngle + (timeline.date.timeIntervalSince1970 * 30).truncatingRemainder(dividingBy: 360)
            AngularGradient(
