import SwiftUI

// MARK: - 液态玻璃视图修饰器
struct LiquidGlassModifierView: ViewModifier {
    @Environment(\.colorScheme) var colorScheme
    var tint: Color
    var radius: CGFloat
    var borderOpacity: CGFloat

    init(tint: Color = .purple, radius: CGFloat = 30, borderOpacity: CGFloat = 0.3) {
        self.tint = tint
        self.radius = radius
        self.borderOpacity = borderOpacity
    }

    func body(content: Content) -> some View {
        content
            .background(
                ZStack {
                    // 基础毛玻璃层
                    if colorScheme == .dark {
                        Color.black.opacity(0.25)
                    } else {
                        Color.white.opacity(0.15)
                    }
                    BackgroundView(tint: tint, radius: radius)
                }
            )
            .clipShape(RoundedRectangle(cornerRadius: radius, style: .continuous))
            .overlay(
                RoundedRectangle(cornerRadius: radius, style: .continuous)
                    .strokeBorder(
                        LinearGradient(
                            colors: [
                                .white.opacity(borderOpacity),
                                tint.opacity(borderOpacity * 0.5),
                                .white.opacity(borderOpacity * 0.3)
                            ],
                            startPoint: .topLeading,
                            endPoint: .bottomTrailing
                        ),
                        lineWidth: 1
                    )
            )
            .shadow(color: .white.opacity(0.15), radius: 8, x: -2, y: -2)
            .shadow(color: .black.opacity(0.12), radius: 15, x: 4, y: 8)
    }
}

private struct BackgroundView: View {
    let tint: Color
    let radius: CGFloat

    var body: some View {
        ZStack {
            Color.clear.background(.ultraThinMaterial)

            RadialGradient(
                colors: [
                    tint.opacity(0.12),
                    tint.opacity(0.06),
                    .clear
                ],
