import Foundation
import CoreLocation
import MapKit
import Combine

@MainActor
class HomeViewModel: ObservableObject {
    // MARK: - 发布属性
    @Published var queryText: String = ""
    @Published var isPlanning: Bool = false
    @Published var isMultiUserMode: Bool = false
    @Published var showFriendPicker: Bool = false
    @Published var mapRegion: MKCoordinateRegion
    @Published var selectedParticipantCount: Int = 1
    @Published var showAlert: Bool = false
    @Published var alertMessage: String = ""

    // 用户位置
    @Published var userLocation: CLLocationCoordinate2D?

    private let locationService = LocationService.shared

    init() {
        // 默认显示北京中心区域
        self.mapRegion = MKCoordinateRegion(
            center: CLLocationCoordinate2D(latitude: 39.9042, longitude: 116.4074),
            span: MKCoordinateSpan(latitudeDelta: 0.05, longitudeDelta: 0.05)
        )
    }

    // MARK: - 获取位置
    func requestLocation() {
        Task {
            do {
                let location = try await locationService.requestCurrentLocation()
                userLocation = location.coordinate
                mapRegion = MKCoordinateRegion(
                    center: location.coordinate,
                    span: MKCoordinateSpan(latitudeDelta: 0.05, longitudeDelta: 0.05)
                )
            } catch {
                // 模拟位置用于演示
                userLocation = CLLocationCoordinate2D(latitude: 39.9042, longitude: 116.4074)
            }
        }
    }

    // MARK: - 开始规划
    func startPlanning() {
        guard !queryText.trimmingCharacters(in: .whitespaces).isEmpty else {
            alertMessage = "请输入路线需求"
            showAlert = true
            return
        }
        isPlanning = true
    }

    // MARK: - 切换多人模式
    func toggleMultiUser() {
        isMultiUserMode.toggle()
        if isMultiUserMode {
            showFriendPicker = true
        }
    }

    // MARK: - 语音输入
    func startVoiceInput() {
        // 语音识别由视图层使用 Speech Recognizer 处理
        // ViewModel 通过 queryText 接收结果
    }

    // MARK: - 搜索地址
    func searchAddress(query: String) async -> [MKMapItem] {
        let request = MKLocalSearch.Request()
        request.naturalLanguageQuery = query
        request.region = mapRegion

        do {
            let response = try await MKLocalSearch(request: request).start()
            return response.mapItems
        } catch {
            alertMessage = "地址搜索失败"
            showAlert = true
            return []
        }
    }
}

import Foundation
import CoreLocation
import SwiftUI

@MainActor
class MultiUserViewModel: ObservableObject {
    @Published var participants: [Participant] = []
    @Published var showingStartPointPicker = false
    @Published var editingParticipantId: String?
    @Published var isAddingParticipant = false

    let maxParticipants = 6

    var canAddMore: Bool {
        participants.count < maxParticipants
    }

    // MARK: - 添加参与者
    func addParticipant(name: String = "", color: Participant.AvatarColor = .blue) {
        guard canAddMore else { return }

        let displayName = name.isEmpty ? "好友\(participants.count + 1)" : name
        let participant = Participant(
            id: UUID().uuidString,
            name: displayName,
            avatarColor: color,
            startCoordinate: CLLocationCoordinate2DCodable(
                latitude: 39.9042 + Double.random(in: -0.02...0.02),
                longitude: 116.4074 + Double.random(in: -0.02...0.02)
            )
        )
        participants.append(participant)
        isAddingParticipant = false
    }

    // MARK: - 删除参与者
    func removeParticipant(_ id: String) {
        participants.removeAll { $0.id == id }
    }

    // MARK: - 更新起点
    func updateStartPoint(for participantId: String, coordinate: CLLocationCoordinate2D) {
        guard let index = participants.firstIndex(where: { $0.id == participantId }) else { return }
        participants[index].startCoordinate = CLLocationCoordinate2DCodable(from: coordinate)
    }

    // MARK: - 更新名称
    func updateName(for participantId: String, name: String) {
        guard let index = participants.firstIndex(where: { $0.id == participantId }) else { return }
        participants[index].name = name
    }

    // MARK: - 更新颜色
    func updateColor(for participantId: String, color: Participant.AvatarColor) {
        guard let index = participants.firstIndex(where: { $0.id == participantId }) else { return }
        participants[index].avatarColor = color
    }

    // MARK: - 清除所有
    func reset() {
        participants.removeAll()
    }

    // MARK: - 预设情侣模式
    func setupCoupleMode() {
        participants = [
            Participant(id: "user_a", name: "我", avatarColor: .blue,
                        startCoordinate: CLLocationCoordinate2DCodable(
                            latitude: 39.9042, longitude: 116.4074)),
            Participant(id: "user_b", name: "TA", avatarColor: .pink,
                        startCoordinate: CLLocationCoordinate2DCodable(
                            latitude: 39.9342, longitude: 116.4574))
        ]
    }
}

import Foundation
import SwiftUI

@MainActor
class RoutePlanningViewModel: ObservableObject {
    // MARK: - 发布属性
    @Published var sessionState: SessionState?
    @Published var isLoading: Bool = false
    @Published var loadingMessage: String = "正在为你计算最优路线..."
    @Published var selectedPlanIndex: Int = 0
    @Published var adjustmentText: String = ""
    @Published var showDetail: Bool = false
    @Published var showTimeline: Bool = false
    @Published var isNavigating: Bool = false
    @Published var navigationProgress: Double = 0
    @Published var errorMessage: String?
    @Published var showError: Bool = false

    // 本地状态快照（撤销/重做）
    private var undoStack: [[RoutePlan]] = []
    private var redoStack: [[RoutePlan]] = []

    // 网络服务
    private let networkService = RouteNetworkService()
    // 是否使用 Mock 模式
    private var useMock: Bool = true

    var currentPlans: [RoutePlan] {
        sessionState?.plans ?? []
    }

    var currentPlan: RoutePlan? {
        sessionState?.plans.indices.contains(selectedPlanIndex) ?? false
            ? sessionState?.plans[selectedPlanIndex]
            : nil
    }

    var participants: [Participant] {
        sessionState?.participants ?? []
    }

    // MARK: - 开始路线规划
    func planRoute(query: String, participants: [Participant]) {
        isLoading = true
        loadingMessage = "正在为你计算最优路线..."
        selectedPlanIndex = 0

        Task {
            do {
                let plans: [RoutePlan]
                if useMock {
                    // 模拟网络延迟
                    try await Task.sleep(nanoseconds: 2_000_000_000)

                    // 根据参与者数量选择不同的 Mock 数据
                    if participants.count >= 2 {
                        plans = MockDataProvider.coupleRoute()
                    } else {
                        plans = MockDataProvider.singleUserRoute()
                    }
                } else {
                    plans = try await networkService.planRoute(
                        query: query,
                        participants: participants
                    )
                }

                let sessionId = UUID().uuidString
                self.sessionState = SessionState(
                    sessionId: sessionId,
                    plans: plans,
                    participants: participants
                )
                self.isLoading = false
                self.showDetail = true
            } catch {
                self.isLoading = false
                self.errorMessage = error.localizedDescription
                self.showError = true
            }
        }
    }

    // MARK: - 选择方案
    func selectPlan(at index: Int) {
        guard let session = sessionState, session.plans.indices.contains(index) else { return }
        selectedPlanIndex = index
        sessionState?.currentPlanIndex = index
    }

    // MARK: - 调整路线
    func adjustRoute(adjustment: String) {
        guard !adjustment.isEmpty, let sessionId = sessionState?.sessionId else { return }

        // 保存当前状态到撤销栈
        if let plans = sessionState?.plans {
            undoStack.append(plans)
            redoStack.removeAll()
        }

        isLoading = true
        loadingMessage = "正在调整路线..."

        Task {
            do {
                let plans: [RoutePlan]
                if useMock {
                    try await Task.sleep(nanoseconds: 1_500_000_000)
                    // 返回调整后的 Mock 数据
                    if adjustment.contains("火锅") || adjustment.contains("不用排队") {
                        plans = MockDataProvider.adjustedRoute()
                    } else {
                        // 原样返回或轻微修改
                        plans = MockDataProvider.singleUserRoute()
                    }
                } else {
                    plans = try await networkService.adjustRoute(
                        sessionId: sessionId,
                        adjustment: adjustment
                    )
                }

                self.sessionState?.plans = plans
                self.selectedPlanIndex = 0
                self.adjustmentText = ""
                self.isLoading = false
            } catch {
                self.isLoading = false
                self.errorMessage = error.localizedDescription
                self.showError = true
            }
        }
    }

    // MARK: - 撤销
    func undo() {
        guard let lastState = undoStack.popLast() else { return }
        if let currentPlans = sessionState?.plans {
            redoStack.append(currentPlans)
        }
        sessionState?.plans = lastState
    }

    // MARK: - 重做
    func redo() {
        guard let nextState = redoStack.popLast() else { return }
        if let currentPlans = sessionState?.plans {
            undoStack.append(currentPlans)
        }
        sessionState?.plans = nextState
    }

    var canUndo: Bool { !undoStack.isEmpty }
    var canRedo: Bool { !redoStack.isEmpty }

    // MARK: - 切换 Mock/网络模式
    func toggleMockMode() {
        useMock.toggle()
    }

    // MARK: - 开始导航模拟
    func startNavigation() {
        isNavigating = true
        navigationProgress = 0

        // 模拟位置更新
        Task {
            let totalSteps = 100
            for step in 1...totalSteps {
                try await Task.sleep(nanoseconds: 500_000_00) // 0.05 秒每步
                navigationProgress = Double(step) / Double(totalSteps)

                if step == totalSteps {
                    isNavigating = false
                    navigationProgress = 1.0
                }
            }
        }
    }

    // MARK: - 重置
    func reset() {
        sessionState = nil
        isLoading = false
        selectedPlanIndex = 0
        adjustmentText = ""
        showDetail = false
        showTimeline = false
        isNavigating = false
        navigationProgress = 0
        undoStack.removeAll()
        redoStack.removeAll()
    }
}

