import SwiftUI
import MapKit

struct HomeView: View {
    @StateObject private var viewModel = HomeViewModel()
    @StateObject private var routeVM = RoutePlanningViewModel()
    @StateObject private var multiUserVM = MultiUserViewModel()

    @Namespace private var heroAnimation

    var body: some View {
        ZStack(alignment: .bottom) {
            // 背景色
            Color(UIColor.systemGroupedBackground)
                .ignoresSafeArea()

            VStack(spacing: 0) {
                // MARK: - 顶部栏
                topBar
                    .padding(.horizontal)
                    .padding(.top, safeAreaTop())

                // MARK: - 地图
                mapSection
                    .frame(height: UIScreen.main.bounds.height * 0.45)

                // MARK: - 底部操作区
                bottomSection
                    .padding(.horizontal)
                    .padding(.top, 16)
            }

            // MARK: - 路线详情（结果页）
            if routeVM.showDetail {
                RouteResultView(
                    viewModel: routeVM,
                    heroAnimation: heroAnimation
                )
                .transition(.move(edge: .bottom))
                .zIndex(10)
            }
        }
        .ignoresSafeArea(.keyboard)
        .fullScreenCover(isPresented: $viewModel.isPlanning) {
            // 全屏加载动画
            RouteLoadingView(viewModel: routeVM) {
                routeVM.planRoute(
                    query: viewModel.queryText,
                    participants: multiUserVM.participants.isEmpty
                        ? [Participant(id: "user_me", name: "我", avatarColor: .blue,
                                       startCoordinate: CLLocationCoordinate2DCodable(
                                        from: viewModel.userLocation ?? CLLocationCoordinate2D(
                                            latitude: 39.9042, longitude: 116.4074)))]
                        : multiUserVM.participants
                )
            }
        }
        .sheet(isPresented: $viewModel.showFriendPicker) {
            FriendPickerView(viewModel: multiUserVM)
                .presentationDetents([.medium, .large])
                .presentationDragIndicator(.visible)
        }
        .alert("提示", isPresented: $viewModel.showAlert) {
            Button("确定") {}
        } message: {
            Text(viewModel.alertMessage)
        }
        .onAppear {
            viewModel.requestLocation()
        }
    }

    // MARK: - 顶部栏
    private var topBar: some View {
        HStack {
            GreetingText()

            Spacer()

            // 好友模式切换
            Button(action: { viewModel.toggleMultiUser() }) {
                HStack(spacing: 6) {
                    Image(systemName: "person.2.fill")
                        .font(.system(size: 14))
                    Text("多人")
                        .font(.system(.subheadline, design: .rounded))
                        .fontWeight(.medium)
                }
                .foregroundColor(.primary)
                .padding(.horizontal, 14)
                .padding(.vertical, 8)
                .glassCard()
            }
        }
    }

    // MARK: - 地图区域
    private var mapSection: some View {
        MapContainerView(
            region: $viewModel.mapRegion,
            annotations: generateAnnotations(),
            polylineData: nil,
            showUserLocation: true
        )
        .overlay(alignment: .topTrailing) {
            // 热门POI气泡
            VStack(alignment: .trailing, spacing: 8) {
                ForEach(0..<3) { i in
                    if i < MockDataProvider.sanlitunPOIs.count {
                        let poi = MockDataProvider.sanlitunPOIs[i]
                        POIBubbleView(poi: poi)
                            .matchedGeometryEffect(id: "poi_\(poi.id)", in: heroAnimation)
                    }
                }
            }
            .padding(.trailing, 12)
            .padding(.top, 12)
        }
    }

    // MARK: - 底部操作区
    private var bottomSection: some View {
        VStack(spacing: 14) {
            // 输入栏
            InputBarView(
                text: $viewModel.queryText,
                onSubmit: { viewModel.startPlanning() },
                onMicTap: { viewModel.startVoiceInput() }
            )

            // 操作按钮
            HStack(spacing: 12) {
                ShimmerButton("路线规划", icon: "map.fill") {
                    viewModel.startPlanning()
                }

                GlassSecondaryButton("发起多人", icon: "person.2.fill") {
                    viewModel.toggleMultiUser()
                }
                .frame(width: 130)
            }
        }
        .padding(.bottom, safeAreaBottom() + 8)
    }

    // MARK: - Helper
    private func generateAnnotations() -> [MapAnnotationItem] {
        var items: [MapAnnotationItem] = []

        // 添加一些附近的POI
        for poi in MockDataProvider.sanlitunPOIs.prefix(3) {
            items.append(MapAnnotationItem(
                coordinate: poi.coordinate.clLocationCoordinate2D,
                title: poi.name,
                subtitle: "\(poi.category.displayName) · \(poi.rating)分",
                type: .poi
            ))
        }

        return items
    }

    private func safeAreaTop() -> CGFloat {
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            return window.safeAreaInsets.top
        }
        return 44
    }

    private func safeAreaBottom() -> CGFloat {
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            return window.safeAreaInsets.bottom
        }
        return 34
    }
}

// MARK: - 热门POI气泡
struct POIBubbleView: View {
