import SwiftUI
import MapKit

struct MapContainerView: UIViewRepresentable {
    @Binding var region: MKCoordinateRegion
    var annotations: [MapAnnotationItem]
    var polylineData: [PolylineData]?
    var showUserLocation: Bool

    func makeUIView(context: Context) -> MKMapView {
        let mapView = MKMapView()
        mapView.delegate = context.coordinator
        mapView.showsUserLocation = showUserLocation
        mapView.setRegion(region, animated: false)

        // 液态玻璃风格
        mapView.layer.cornerRadius = 30
        mapView.layer.masksToBounds = true
        mapView.layer.maskedCorners = [.layerMinXMaxYCorner, .layerMaxXMaxYCorner]

        return mapView
    }

    func updateUIView(_ mapView: MKMapView, context: Context) {
        // Update region
        mapView.setRegion(region, animated: true)

        // 清除旧标注
        mapView.removeAnnotations(mapView.annotations.filter { !($0 is MKUserLocation) })
        mapView.removeOverlays(mapView.overlays)

        // 添加新标注
        for annotation in annotations {
            let mkAnnotation = MKPointAnnotation()
            mkAnnotation.title = annotation.title
            mkAnnotation.subtitle = annotation.subtitle
            mkAnnotation.coordinate = annotation.coordinate
            mapView.addAnnotation(mkAnnotation)
        }

        // 添加路线覆盖
        if let polylineData = polylineData {
            for data in polylineData {
                let polyline = MKPolyline(coordinates: data.coordinates, count: data.coordinates.count)
                polyline.title = data.color.rawValue
                mapView.addOverlay(polyline)
            }
        }
    }

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    class Coordinator: NSObject, MKMapViewDelegate {
        var parent: MapContainerView

        init(_ parent: MapContainerView) {
            self.parent = parent
        }

        func mapView(_ mapView: MKMapView, rendererFor overlay: MKOverlay) -> MKOverlayRenderer {
            if let polyline = overlay as? MKPolyline {
                let renderer = MKPolylineRenderer(polyline: polyline)
                renderer.lineWidth = 3
                renderer.lineCap = .round
                renderer.lineJoin = .round

                if let colorString = polyline.title,
                   let color = PolylineColor(rawValue: colorString)?.color {
                    renderer.strokeColor = color.withAlphaComponent(0.7)
                } else {
                    renderer.strokeColor = UIColor.systemPurple.withAlphaComponent(0.7)
                }

                return renderer
            }
            return MKOverlayRenderer(overlay: overlay)
        }

        func mapView(_ mapView: MKMapView, viewFor annotation: MKAnnotation) -> MKAnnotationView? {
            if annotation is MKUserLocation {
                return nil
            }

            let identifier = "POIAnnotation"
            var annotationView = mapView.dequeueReusableAnnotationView(withIdentifier: identifier)

            if annotationView == nil {
                annotationView = MKMarkerAnnotationView(annotation: annotation, reuseIdentifier: identifier)
                annotationView?.canShowCallout = true
            } else {
                annotationView?.annotation = annotation
            }

            return annotationView
        }
    }
}

// MARK: - 辅助模型
struct MapAnnotationItem: Identifiable {
    let id = UUID()
    let coordinate: CLLocationCoordinate2D
    let title: String
    let subtitle: String?
    let type: AnnotationType

    enum AnnotationType {
        case poi
        case meetingPoint
        case startPoint(color: PolylineColor)
        case userLocation
    }
}

struct PolylineData: Identifiable {
    let id = UUID()
    let coordinates: [CLLocationCoordinate2D]
    let color: PolylineColor
}

enum PolylineColor: String {
    case purple = "purple"
    case blue = "blue"
    case pink = "pink"
    case green = "green"
    case orange = "orange"

    var color: UIColor {
        switch self {
        case .purple: return .systemPurple
        case .blue: return .systemBlue
        case .pink: return .systemPink
        case .green: return .systemGreen
        case .orange: return .systemOrange
        }
    }
}

import SwiftUI

struct InputBarView: View {
    @Binding var text: String
    var onSubmit: () -> Void
    var onMicTap: () -> Void

    @FocusState private var isFocused: Bool
    @State private var gradientRotation: Double = 0

    var body: some View {
        HStack(spacing: 12) {
            // 文本输入
            TextField("比如：想吃火锅再去看展，预算 300，不排队", text: $text)
                .focused($isFocused)
                .font(.system(.body, design: .rounded))
                .foregroundColor(.primary)
                .autocorrectionDisabled()
                .submitLabel(.search)
                .onSubmit(onSubmit)

            // 语音输入按钮
            Button(action: onMicTap) {
                Image(systemName: "mic.fill")
                    .font(.system(size: 16, weight: .medium))
                    .foregroundColor(.purple.opacity(0.7))
                    .frame(width: 36, height: 36)
                    .background(
                        Circle()
                            .fill(.ultraThinMaterial)
                    )
            }
        }
        .padding(.horizontal, 16)
        .padding(.vertical, 14)
        .background(
            ZStack {
                Color.clear.background(.ultraThinMaterial)
                RadialGradient(
                    colors: [Color.purple.opacity(0.06), .clear],
                    center: .topLeading,
                    startRadius: 0,
                    endRadius: 200
                )
            }
        )
        .clipShape(RoundedRectangle(cornerRadius: 28, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 28, style: .continuous)
                .stroke(
                    isFocused
                    ? AnyShapeStyle(
                        AngularGradient(
                            colors: [.purple, .blue, .cyan, .purple],
                            center: .center,
                            startAngle: .degrees(gradientRotation),
                            endAngle: .degrees(gradientRotation + 360)
                        )
                    )
                    : AnyShapeStyle(.white.opacity(0.2)),
                    lineWidth: isFocused ? 2 : 1
                )
        )
        .shadow(color: .black.opacity(0.05), radius: 10, x: 0, y: 5)
        .onChange(of: isFocused) { focused in
            if focused {
                withAnimation(.linear(duration: 3).repeatForever(autoreverses: false)) {
                    gradientRotation = 360
                }
            } else {
                gradientRotation = 0
            }
        }
        .onTapGesture { isFocused = true }
    }
}

