                ForEach(0..<3) { i in
                    if i < MockDataProvider.sanlitunPOIs.count {
                        let poi = MockDataProvider.sanlitunPOIs[i]
                        POIBubbleView(poi: poi)
                            .matchedGeometryEffect(id: "poi_\(poi.id)", in: heroAnimation)
                    }
                }
            }
            .padding(.trailing, 12)
            .padding(.top, 12)
        }
    }

    // MARK: - 底部操作区
    private var bottomSection: some View {
        VStack(spacing: 14) {
            // 输入栏
            InputBarView(
                text: $viewModel.queryText,
                onSubmit: { viewModel.startPlanning() },
                onMicTap: { viewModel.startVoiceInput() }
