struct RouteTimelineView: View {
    let plan: RoutePlan
    let participants: [Participant]

    @Environment(\.dismiss) var dismiss

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(alignment: .leading, spacing: 0) {
                    // 标题区域
                    headerSection

                    // 总览
                    overviewSection
                        .padding(.horizontal)

                    // 时间线
