                            .foregroundColor(.white)
                            .frame(width: 36, height: 36)
                            .background(Circle().fill(Color.purple.gradient))

                        Text(poi.name)
                            .font(.system(.caption, design: .rounded))
                            .fontWeight(.medium)
                            .multilineTextAlignment(.center)
                            .lineLimit(2)
                            .frame(width: 70)
                    }

                    if index < plan.pois.count - 1 {
                        VStack(spacing: 2) {
                            if let segment = plan.segments.first(where: { $0.fromPOI.id == poi.id }) {
                                Image(systemName: segment.transportMode.iconName)
                                    .font(.system(size: 12))
                                    .foregroundColor(.secondary)
                                Text(segment.transportMode.displayName)
                                    .font(.system(.caption2, design: .rounded))
                                    .foregroundColor(.secondary)
                                Text(formatDuration(segment.duration))
                                    .font(.system(.caption2, design: .rounded))
                                    .foregroundColor(.secondary)
                            }
                        }
                        .frame(width: 50)
                    }
                }
            }
            .padding()
            .glassCard()
        }
    }

    // MARK: - 时间线
    private var timelineSection: some View {
        VStack(alignment: .leading, spacing: 16) {
            Text("时间安排")
                .font(.system(.headline, design: .rounded))
                .fontWeight(.semibold)

            VStack(spacing: 0) {
                ForEach(Array(plan.pois.enumerated()), id: \.element.id) { index, poi in
                    TimelineItemView(
                        poi: poi,
                        isFirst: index == 0,
                        isLast: index == plan.pois.count - 1
                    )
                }

                // 交通段
                ForEach(plan.segments) { segment in
                    TransportSegmentView(segment: segment)
                }
            }
            .padding()
            .glassCard()
        }
    }

    // MARK: - 参与者
    private var participantsSection: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text("成员行程")
                .font(.system(.headline, design: .rounded))
                .fontWeight(.semibold)

            ForEach(participants) { participant in
                ParticipantTimelineRow(participant: participant)
            }
        }
    }

    // MARK: - Helper
    private func tagLabel(_ tag: RoutePlan.RouteTag) -> some View {
        Text(tag.rawValue)
            .font(.system(.caption2, design: .rounded))
            .fontWeight(.bold)
            .foregroundColor(.white)
            .padding(.horizontal, 10)
            .padding(.vertical, 4)
            .background(tagColor(tag))
            .clipShape(Capsule())
    }

    private func tagColor(_ tag: RoutePlan.RouteTag) -> Color {
        switch tag {
        case .experience: return .purple
        case .fastest: return .blue
        case .cheapest: return .green
        }
    }

    private func formatDuration(_ duration: TimeInterval) -> String {
        let minutes = Int(duration) / 60
        if minutes >= 60 {
            return "\(minutes / 60)h\(minutes % 60)min"
        }
        return "\(minutes)min"
    }
}

