// MARK: - 交通段视图
struct TransportSegmentView: View {
    let segment: RouteSegment

    var body: some View {
        HStack(spacing: 14) {
            // 连接线
            VStack(spacing: 0) {
                Rectangle()
                    .fill(Color.secondary.opacity(0.3))
                    .frame(width: 2, height: 10)
                Image(systemName: segment.transportMode.iconName)
                    .font(.system(size: 12))
                    .foregroundColor(.secondary)
                    .frame(width: 20, height: 20)
                    .background(Circle().fill(.ultraThinMaterial))
                Rectangle()
                    .fill(Color.secondary.opacity(0.3))
                    .frame(width: 2, height: 10)
            }

            Text("\(segment.transportMode.displayName) \(formatDistance(segment.distance))，约\(formatDuration(segment.duration))")
                .font(.system(.caption, design: .rounded))
                .foregroundColor(.secondary)
                .padding(.leading, 8)

            Spacer()
