    private func formatDistance(_ distance: Double) -> String {
        if distance >= 1000 {
            return "\(String(format: "%.1f", distance / 1000))km"
        }
        return "\(Int(distance))m"
    }

    private func formatDuration(_ duration: TimeInterval) -> String {
        let minutes = Int(duration) / 60
        return "\(minutes)分钟"
    }
}

