import SwiftUI
import MapKit

struct RouteResultView: View {
    @ObservedObject var viewModel: RoutePlanningViewModel
    let heroAnimation: Namespace.ID

    @State private var selectedCardIndex: Int = 0
    @State private var mapRegion: MKCoordinateRegion

    init(viewModel: RoutePlanningViewModel, heroAnimation: Namespace.ID) {
        self.viewModel = viewModel
        self.heroAnimation = heroAnimation
        _mapRegion = State(initialValue: MKCoordinateRegion(
            center: CLLocationCoordinate2D(latitude: 39.92, longitude: 116.42),
            span: MKCoordinateSpan(latitudeDelta: 0.05, longitudeDelta: 0.05)
        ))
    }

    var body: some View {
        ZStack(alignment: .bottom) {
            VStack(spacing: 0) {
                // MARK: - 顶部栏
                topBar

                // MARK: - 地图
                mapSection
                    .frame(height: UIScreen.main.bounds.height * 0.3)

                // MARK: - 方案选择
                planSelector
                    .padding(.top, 8)

                // MARK: - 卡片流
                cardScroll
                    .padding(.top, 8)

                // MARK: - 调整输入
                adjustmentSection
                    .padding(.horizontal)
                    .padding(.top, 8)
            }

            // MARK: - 底部操作栏
            bottomActionBar
        }
        .background(Color(UIColor.systemGroupedBackground))
        .fullScreenCover(isPresented: $viewModel.isLoading) {
            RouteLoadingView(viewModel: viewModel) {
                // Loading already triggered
            }
        }
        .sheet(isPresented: $viewModel.showTimeline) {
            if let plan = viewModel.currentPlan {
                RouteTimelineView(
                    plan: plan,
                    participants: viewModel.participants
                )
            }
        }
    }

    // MARK: - 顶部栏
    private var topBar: some View {
        HStack {
            Button(action: { viewModel.reset() }) {
                HStack(spacing: 4) {
                    Image(systemName: "chevron.left")
                        .font(.system(size: 14, weight: .semibold))
                    Text("返回")
                        .font(.system(.body, design: .rounded))
                }
                .foregroundColor(.purple)
            }

            Spacer()

            Text("路线方案")
                .font(.system(.headline, design: .rounded))
                .fontWeight(.semibold)

            Spacer()

            // 撤销/重做
            HStack(spacing: 12) {
                Button(action: { viewModel.undo() }) {
                    Image(systemName: "arrow.uturn.backward")
                        .foregroundColor(viewModel.canUndo ? .purple : .secondary.opacity(0.3))
                }
                .disabled(!viewModel.canUndo)

                Button(action: { viewModel.redo() }) {
                    Image(systemName: "arrow.uturn.forward")
                        .foregroundColor(viewModel.canRedo ? .purple : .secondary.opacity(0.3))
                }
                .disabled(!viewModel.canRedo)
            }
            .font(.system(size: 16))
        }
        .padding(.horizontal)
        .padding(.vertical, 12)
        .background(.ultraThinMaterial)
    }

    // MARK: - 地图
    private var mapSection: some View {
        MapContainerView(
            region: $mapRegion,
            annotations: generateAnnotations(),
            polylineData: generatePolyline()
        )
        .overlay(alignment: .topTrailing) {
            if viewModel.participants.count > 1 {
                // 会合点标注
                Label("会合点", systemImage: "heart.fill")
                    .font(.system(.caption, design: .rounded))
                    .foregroundColor(.pink)
                    .padding(.horizontal, 10)
                    .padding(.vertical, 5)
                    .background(.ultraThinMaterial)
                    .clipShape(Capsule())
                    .padding(8)
            }
        }
    }

    // MARK: - 方案选择标签
    private var planSelector: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 8) {
                ForEach(Array(viewModel.currentPlans.enumerated()), id: \.element.id) { index, plan in
                    Button(action: {
                        withAnimation(.spring(response: 0.35, dampingFraction: 0.8)) {
                            selectedCardIndex = index
                            viewModel.selectPlan(at: index)
                        }
                    }) {
                        HStack(spacing: 4) {
                            Circle()
                                .fill(selectedCardIndex == index ? Color.purple : Color.secondary.opacity(0.3))
                                .frame(width: 6, height: 6)
                            Text(plan.tag.rawValue)
                                .font(.system(.caption, design: .rounded))
                                .fontWeight(selectedCardIndex == index ? .semibold : .regular)
                        }
                        .foregroundColor(selectedCardIndex == index ? .purple : .secondary)
                        .padding(.horizontal, 14)
                        .padding(.vertical, 8)
                        .background(
                            selectedCardIndex == index
                            ? Color.purple.opacity(0.1)
                            : Color.clear
                        )
                        .clipShape(Capsule())
                        .overlay(
                            Capsule()
                                .stroke(selectedCardIndex == index ? Color.purple.opacity(0.3) : .clear, lineWidth: 1)
                        )
                    }
                }
            }
            .padding(.horizontal)
        }
    }

    // MARK: - 卡片流
    private var cardScroll: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            LazyHStack(spacing: 16) {
                ForEach(Array(viewModel.currentPlans.enumerated()), id: \.element.id) { index, plan in
                    RouteCardView(
                        plan: plan,
                        isSelected: index == selectedCardIndex,
                        namespace: heroAnimation
                    )
                    .scrollTransition(.interactive, axis: .horizontal) { content, phase in
                        content
                            .opacity(phase.isIdentity ? 1 : 0.7)
                            .scaleEffect(phase.isIdentity ? 1 : 0.9)
                            .blur(radius: phase.isIdentity ? 0 : 2)
                    }
                    .onTapGesture {
                        selectedCardIndex = index
                        viewModel.selectPlan(at: index)
                        viewModel.showTimeline = true
                    }
                }
            }
            .padding(.horizontal)
            .scrollTargetLayout()
        }
        .scrollTargetBehavior(.viewAligned)
        .frame(height: 320)
        .onChange(of: selectedCardIndex) { newIndex in
            viewModel.selectPlan(at: newIndex)
        }
    }

    // MARK: - 调整输入
    private var adjustmentSection: some View {
        HStack(spacing: 10) {
            GradientBorderTextField(
                text: $viewModel.adjustmentText,
                placeholder: "输入调整需求，如：换一家不用排队的咖啡店",
                onSubmit: {
                    guard !viewModel.adjustmentText.isEmpty else { return }
                    viewModel.adjustRoute(adjustment: viewModel.adjustmentText)
                },
                onMicTap: {}
            )

            Button(action: {
                guard !viewModel.adjustmentText.isEmpty else { return }
                viewModel.adjustRoute(adjustment: viewModel.adjustmentText)
            }) {
                Image(systemName: "arrow.up.circle.fill")
                    .font(.system(size: 32))
                    .foregroundColor(.purple)
                    .opacity(viewModel.adjustmentText.isEmpty ? 0.4 : 1)
            }
            .disabled(viewModel.adjustmentText.isEmpty)
        }
    }

    // MARK: - 底部操作栏
    private var bottomActionBar: some View {
        HStack(spacing: 16) {
            // 查看详细日程
            GlassSecondaryButton(title: "详细日程", icon: "list.star") {
                viewModel.showTimeline = true
            }

            // 开始导航
            ShimmerButton("开始导航", icon: "location.fill") {
                viewModel.startNavigation()
            }
        }
        .padding(.horizontal)
        .padding(.vertical, 12)
        .background(.ultraThinMaterial)
    }

    // MARK: - Helper
    private func generateAnnotations() -> [MapAnnotationItem] {
        guard let plan = viewModel.currentPlan else { return [] }
        var items: [MapAnnotationItem] = []

        for poi in plan.pois {
            items.append(MapAnnotationItem(
                coordinate: poi.coordinate.clLocationCoordinate2D,
                title: poi.name,
                subtitle: "\(poi.category.displayName)",
                type: .poi
            ))
        }

        // 会合点
        if viewModel.participants.count > 1, let firstPOI = plan.pois.first {
            items.append(MapAnnotationItem(
                coordinate: firstPOI.coordinate.clLocationCoordinate2D,
                title: "会合点",
                subtitle: "\(firstPOI.name)",
                type: .meetingPoint
            ))
        }

        // 参与者起点
        for participant in viewModel.participants {
            items.append(MapAnnotationItem(
                coordinate: participant.startCoordinate.clLocationCoordinate2D,
                title: participant.name,
                subtitle: "起点",
                type: .startPoint(color: participantColor(participant))
            ))
        }

        return items
    }

    private func generatePolyline() -> [PolylineData]? {
        guard let plan = viewModel.currentPlan else { return nil }
        let coordinates = plan.pois.map { $0.coordinate.clLocationCoordinate2D }
        return [PolylineData(coordinates: coordinates, color: .purple)]
    }

    private func participantColor(_ participant: Participant) -> PolylineColor {
        switch participant.avatarColor {
        case .blue: return .blue
        case .pink: return .pink
        case .green: return .green
        case .orange: return .orange
        case .purple, .teal: return .purple
        }
    }
}

// MARK: - Helper Button
struct GlassSecondaryButton: View {
    let title: LocalizedStringKey
    let icon: String
    let action: () -> Void

    @State private var isPressed = false

    var body: some View {
        Button(action: {
            withAnimation(.spring(response: 0.3, dampingFraction: 0.6)) {
                isPressed = true
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.15) {
                isPressed = false
            }
            action()
        }) {
            HStack(spacing: 6) {
                Image(systemName: icon)
                    .font(.system(size: 13, weight: .medium))
                Text(title)
                    .font(.system(.subheadline, design: .rounded))
                    .fontWeight(.medium)
            }
            .foregroundColor(.primary)
            .frame(height: 44)
            .frame(maxWidth: .infinity)
            .glassButton()
            .scaleEffect(isPressed ? 0.95 : 1.0)
        }
    }
}

