import SwiftUI
import MapKit

struct FriendPickerView: View {
    @ObservedObject var viewModel: MultiUserViewModel
    @Environment(\.dismiss) var dismiss

    @State private var newName: String = ""
    @State private var newColor: Participant.AvatarColor = .blue
    @State private var showAddForm: Bool = false

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(alignment: .leading, spacing: 16) {
                    // 说明
                    Text("添加同行好友，设置各自起点后开始规划")
                        .font(.system(.subheadline, design: .rounded))
                        .foregroundColor(.secondary)
                        .padding(.horizontal)

                    // 已有参与者
                    if viewModel.participants.isEmpty {
                        emptyState
                    } else {
                        participantsList
                    }

                    // 添加按钮
                    if viewModel.canAddMore {
                        if showAddForm {
                            addForm
                        } else {
                            addButton
                        }
                    }

                    // 情侣模式快捷设置
                    if viewModel.participants.isEmpty {
                        quickSetupButton
                    }
                }
                .padding(.vertical)
            }
            .background(Color(UIColor.systemGroupedBackground))
            .navigationTitle("添加同行好友")
            .navigationBarTitleDisplayMode(.large)
            .toolbar {
                ToolbarItem(placement: .topBarLeading) {
                    Button("取消") { dismiss() }
                        .foregroundColor(.purple)
                }
                ToolbarItem(placement: .topBarTrailing) {
                    Button("完成") {
                        if !viewModel.participants.isEmpty {
                            dismiss()
                        }
                    }
                    .fontWeight(.semibold)
                    .foregroundColor(viewModel.participants.isEmpty ? .secondary : .purple)
                    .disabled(viewModel.participants.isEmpty)
                }
            }
        }
    }

    // MARK: - 空状态
    private var emptyState: some View {
        VStack(spacing: 20) {
            Image(systemName: "person.3.fill")
                .font(.system(size: 60))
                .foregroundColor(.purple.opacity(0.4))

            Text("还没有添加同行好友")
                .font(.system(.body, design: .rounded))
                .foregroundColor(.secondary)

            Text("点击下方按钮添加好友，\n或使用情侣模式快速设置")
                .font(.system(.caption, design: .rounded))
                .foregroundColor(.secondary)
                .multilineTextAlignment(.center)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 40)
        .glassCard()
        .padding(.horizontal)
    }

    // MARK: - 参与者列表
    private var participantsList: some View {
        VStack(spacing: 10) {
            ForEach(viewModel.participants) { participant in
                ParticipantRow(
                    participant: participant,
                    onEdit: {
                        viewModel.editingParticipantId = participant.id
                        viewModel.showingStartPointPicker = true
                    },
                    onDelete: {
                        withAnimation {
                            viewModel.removeParticipant(participant.id)
                        }
                    }
                )
            }
        }
        .padding(.horizontal)
    }

    // MARK: - 添加按钮
    private var addButton: some View {
        Button(action: {
            withAnimation(.spring(response: 0.35, dampingFraction: 0.8)) {
                showAddForm = true
                newName = ""
                newColor = Participant.AvatarColor.allCases.randomElement() ?? .blue
            }
        }) {
            HStack {
                Image(systemName: "plus.circle.fill")
                    .font(.system(size: 20))
                Text("添加好友")
                    .font(.system(.body, design: .rounded))
                    .fontWeight(.medium)
            }
            .foregroundColor(.purple)
            .frame(maxWidth: .infinity)
            .frame(height: 50)
            .glassButton()
        }
        .padding(.horizontal)
    }

    // MARK: - 添加表单
    private var addForm: some View {
        VStack(spacing: 14) {
            // 名称输入
            HStack {
                TextField("输入好友名称", text: $newName)
                    .font(.system(.body, design: .rounded))

                // 颜色选择
                HStack(spacing: 6) {
                    ForEach(Participant.AvatarColor.allCases, id: \.rawValue) { color in
                        Circle()
                            .fill(color.color)
                            .frame(width: 24, height: 24)
                            .overlay(
                                Circle()
                                    .stroke(color == newColor ? Color.white : .clear, lineWidth: 2)
                            )
                            .shadow(color: color == newColor ? color.color.opacity(0.5) : .clear, radius: 4)
                            .onTapGesture {
                                withAnimation { newColor = color }
                            }
                    }
                }
            }
            .padding(12)
            .glassCard()

            // 确认/取消
            HStack(spacing: 12) {
                Button("取消") {
                    withAnimation {
                        showAddForm = false
                    }
                }
                .foregroundColor(.secondary)
                .frame(maxWidth: .infinity)
                .frame(height: 40)
                .glassButton()

                Button("添加") {
                    withAnimation {
                        viewModel.addParticipant(name: newName, color: newColor)
                        showAddForm = false
                    }
                }
                .foregroundColor(.white)
                .frame(maxWidth: .infinity)
                .frame(height: 40)
                .background(
                    LinearGradient(colors: [.purple, .blue], startPoint: .leading, endPoint: .trailing)
                )
                .clipShape(RoundedRectangle(cornerRadius: 30, style: .continuous))
            }
        }
        .padding(.horizontal)
        .transition(.move(edge: .top).combined(with: .opacity))
    }

    // MARK: - 快捷设置
    private var quickSetupButton: some View {
        Button(action: {
            withAnimation {
                viewModel.setupCoupleMode()
            }
        }) {
            HStack {
                Image(systemName: "heart.fill")
                    .font(.system(size: 16))
                    .foregroundColor(.pink)
                Text("快速设置：情侣模式")
                    .font(.system(.body, design: .rounded))
                    .fontWeight(.medium)
                Spacer()
                Image(systemName: "chevron.right")
                    .font(.system(size: 12))
                    .foregroundColor(.secondary)
            }
            .foregroundColor(.primary)
            .padding()
            .glassCard()
        }
        .padding(.horizontal)
    }
}

// MARK: - 参与者行
struct ParticipantRow: View {
    let participant: Participant
    let onEdit: () -> Void
    let onDelete: () -> Void

    var body: some View {
        HStack(spacing: 12) {
            // 头像
            Circle()
                .fill(participant.avatarColor.color)
                .frame(width: 44, height: 44)
                .overlay(
                    Text(String(participant.name.prefix(1)))
                        .font(.system(.title3, design: .rounded))
                        .fontWeight(.bold)
                        .foregroundColor(.white)
                )

            VStack(alignment: .leading, spacing: 2) {
                Text(participant.name)
                    .font(.system(.body, design: .rounded))
                    .fontWeight(.medium)

                Text("长按选择起点位置")
                    .font(.system(.caption, design: .rounded))
                    .foregroundColor(.secondary)
            }

            Spacer()

            // 起点编辑按钮
            Button(action: onEdit) {
                Image(systemName: "mappin.and.ellipse")
                    .font(.system(size: 14))
                    .foregroundColor(.purple)
                    .frame(width: 32, height: 32)
                    .background(Circle().fill(.ultraThinMaterial))
            }

            // 删除
