            ZStack(alignment: .top) {
                // 地图
                MapContainerView(
                    region: $mapRegion,
                    annotations: annotations,
                    polylineData: nil,
                    showUserLocation: true
                )
                .edgesIgnoringSafeArea(.all)

                // 搜索栏
                VStack {
                    searchBar
                        .padding(.horizontal)
                        .padding(.top, safeAreaTop())

                    if !searchResults.isEmpty {
                        searchResultsList
                            .padding(.horizontal)
                    }

                    Spacer()

                    // 图钉指示
                    Image(systemName: "mappin.circle.fill")
                        .font(.system(size: 40))
                        .foregroundColor(.purple)
                        .shadow(color: .white.opacity(0.5), radius: 5)
                        .offset(y: -20)

                    Spacer()

                    // 确认按钮
                    if let coord = selectedCoordinate ?? mapRegion.center as CLLocationCoordinate2D? {
                        Button(action: {
                            viewModel.updateStartPoint(for: participantId, coordinate: coord)
                            dismiss()
                        }) {
                            Text("确认此位置")
                                .font(.system(.body, design: .rounded))
                                .fontWeight(.semibold)
                                .foregroundColor(.white)
                                .frame(maxWidth: .infinity)
                                .frame(height: 50)
                                .background(
                                    LinearGradient(colors: [.purple, .blue], startPoint: .leading, endPoint: .trailing)
                                )
                                .clipShape(RoundedRectangle(cornerRadius: 30, style: .continuous))
                                .shadow(color: .purple.opacity(0.3), radius: 15, y: 5)
                        }
                        .padding(.horizontal)
                        .padding(.bottom, 30)
                    }
                }
            }
            .navigationTitle("选择起点 - \(participant?.name ?? "")")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button("完成") { dismiss() }
                        .foregroundColor(.purple)
                }
            }
        }
    }

    // MARK: - 搜索栏
    private var searchBar: some View {
        HStack(spacing: 10) {
            Image(systemName: "magnifyingglass")
                .foregroundColor(.secondary)
            TextField("搜索地址", text: $searchText)
                .font(.system(.body, design: .rounded))
                .onSubmit { performSearch() }
                .submitLabel(.search)

