                title: participant?.name ?? "起点",
                subtitle: "拖动地图调整位置",
                type: .startPoint(color: participantColor)
            )
        ]
    }

    private var participantColor: PolylineColor {
        guard let p = participant else { return .purple }
        switch p.avatarColor {
        case .blue: return .blue
        case .pink: return .pink
        case .green: return .green
        case .orange: return .orange
        case .purple, .teal: return .purple
        }
    }

