    var opacity: Double
    var radius: CGFloat

    init(tint: Color = .purple, opacity: Double = 0.1, radius: CGFloat = 30) {
        self.tint = tint
        self.opacity = opacity
        self.radius = radius
    }

    func body(content: Content) -> some View {
        content
            .background(
                ZStack {
                    // 毛玻璃基底
                    Color.clear
                        .background(.ultraThinMaterial)

