                    RadialGradient(
                        colors: [
                            tint.opacity(opacity),
                            tint.opacity(opacity * 0.5),
                            .clear
                        ],
                        center: .topLeading,
                        startRadius: 0,
                        endRadius: radius * 4
                    )

                    // 边缘高光
                    RadialGradient(
                        colors: [
                            .white.opacity(0.15),
                            .clear
                        ],
                        center: .topLeading,
                        startRadius: 0,
                        endRadius: radius * 2
                    )
