import SwiftUI

struct ShimmerButton: View {
    let title: LocalizedStringKey
    let icon: String?
    let action: () -> Void

    @State private var isPressed = false
    @State private var rippleActive = false
    @State private var shimmerOffset: CGFloat = -0.5

    init(_ title: LocalizedStringKey, icon: String? = nil, action: @escaping () -> Void) {
        self.title = title
        self.icon = icon
        self.action = action
    }

    var body: some View {
        Button(action: {
            withAnimation(.spring(response: 0.3, dampingFraction: 0.6)) {
                isPressed = true
                rippleActive = true
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.15) {
                isPressed = false
            }
            action()
        }) {
            HStack(spacing: 10) {
                if let icon = icon {
                    Image(systemName: icon)
                        .font(.system(size: 16, weight: .semibold))
                }
                Text(title)
                    .font(.system(.body, design: .rounded))
                    .fontWeight(.semibold)
            }
            .foregroundColor(.white)
            .frame(minHeight: 52)
            .frame(maxWidth: .infinity)
            .background(
                ZStack {
                    // 毛玻璃基底
                    Color.clear.background(.ultraThinMaterial)

                    // 紫色渐变
                    LinearGradient(
                        colors: [
                            .purple.opacity(0.5),
                            .blue.opacity(0.4),
                            .purple.opacity(0.5)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )

                    // 边缘高光
                    RadialGradient(
                        colors: [.white.opacity(0.2), .clear],
                        center: .topLeading,
                        startRadius: 0,
                        endRadius: 100
                    )

                    // Shimmer 扫描线
                    GeometryReader { geo in
                        LinearGradient(
                            colors: [
                                .clear,
                                .white.opacity(0.15),
                                .clear
                            ],
                            startPoint: .leading,
                            endPoint: .trailing
                        )
                        .frame(width: geo.size.width * 0.4)
                        .offset(x: shimmerOffset * geo.size.width)
                        .blur(radius: 10)
                        .onAppear {
                            withAnimation(.linear(duration: 2.5).repeatForever(autoreverses: false)) {
                                shimmerOffset = 1.5
                            }
                        }
                    }
                    .clipShape(RoundedRectangle(cornerRadius: 30, style: .continuous))
                }
            )
            .clipShape(RoundedRectangle(cornerRadius: 30, style: .continuous))
            .overlay(
                RoundedRectangle(cornerRadius: 30, style: .continuous)
                    .stroke(.white.opacity(0.25), lineWidth: 1)
            )
            .scaleEffect(isPressed ? 0.95 : 1.0)
            .shadow(color: .purple.opacity(0.25), radius: isPressed ? 5 : 15, x: 0, y: isPressed ? 2 : 8)
        }
        .rippleEffect(isActive: $rippleActive)
    }
}

