import SwiftUI

struct RouteCardView: View {
    let plan: RoutePlan
    let isSelected: Bool
    let namespace: Namespace.ID

    @State private var showExplanation: Bool = false

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            // 方案标签
            HStack {
                tagLabel(plan.tag)
                Spacer()
                if isSelected {
                    Image(systemName: "checkmark.circle.fill")
                        .foregroundColor(.purple)
                        .font(.system(size: 20))
                }
            }

            // POI 串联简图
            POIChainView(pois: plan.pois)

            // 路线概览
            HStack(spacing: 16) {
                // 时长
                HStack(spacing: 4) {
                    Image(systemName: "clock.fill")
                        .font(.system(size: 12))
                        .foregroundColor(.purple)
                    Text(plan.formattedDuration)
                        .font(.system(.caption, design: .rounded))
                        .fontWeight(.medium)
                }

                // 花费
                HStack(spacing: 4) {
                    Image(systemName: "yensign.circle.fill")
                        .font(.system(size: 12))
                        .foregroundColor(.orange)
                    Text(plan.formattedCost)
                        .font(.system(.caption, design: .rounded))
                        .fontWeight(.medium)
                }

                Spacer()

                // 详情按钮
                Button(action: { showExplanation.toggle() }) {
                    HStack(spacing: 4) {
                        Text("推荐理由")
                            .font(.system(.caption, design: .rounded))
                        Image(systemName: showExplanation ? "chevron.up" : "chevron.down")
                            .font(.system(size: 10))
                    }
                    .foregroundColor(.purple)
                }
            }

            // 推荐理由
            if showExplanation {
                Text(plan.explanation)
                    .font(.system(.caption, design: .rounded))
                    .foregroundColor(.secondary)
                    .lineLimit(4)
                    .transition(.opacity.combined(with: .move(edge: .top)))
            }

            // POI 缩略信息列表
            ForEach(plan.pois) { poi in
                POISummaryRow(poi: poi)
            }
        }
        .padding(16)
        .frame(width: UIScreen.main.bounds.width - 64)
        .glassCard()
        .matchedGeometryEffect(id: "card_\(plan.id)", in: namespace)
        .overlay(
            RoundedRectangle(cornerRadius: 24, style: .continuous)
                .stroke(isSelected ? Color.purple.opacity(0.5) : .clear, lineWidth: 2)
        )
        .animation(.spring(response: 0.35, dampingFraction: 0.8), value: showExplanation)
    }

    private func tagLabel(_ tag: RoutePlan.RouteTag) -> some View {
        Text(tag.rawValue)
            .font(.system(.caption2, design: .rounded))
            .fontWeight(.bold)
            .foregroundColor(.white)
            .padding(.horizontal, 10)
            .padding(.vertical, 4)
            .background(tagColor(tag))
            .clipShape(Capsule())
    }

    private func tagColor(_ tag: RoutePlan.RouteTag) -> Color {
        switch tag {
        case .experience: return .purple
        case .fastest: return .blue
        case .cheapest: return .green
        }
    }
}

