                        .font(.system(size: 14))
                        .foregroundColor(.purple)
                        .frame(width: 28, height: 28)
                        .background(Circle().fill(.ultraThinMaterial))

                    Text(poi.name.prefix(4) + (poi.name.count > 4 ? ".." : ""))
                        .font(.system(.caption2, design: .rounded))
                        .foregroundColor(.secondary)
                }

                if index < pois.count - 1 {
                    Image(systemName: "arrow.right")
                        .font(.system(size: 10))
                        .foregroundColor(.secondary.opacity(0.5))
                }
            }
        }
    }
}

// MARK: - POI 摘要行
struct POISummaryRow: View {
    let poi: POI

    var body: some View {
        HStack(spacing: 10) {
            // 分类图标
            Image(systemName: poi.category.iconName)
                .font(.system(size: 14))
                .foregroundColor(.purple)
                .frame(width: 32, height: 32)
                .background(Circle().fill(.ultraThinMaterial))

            VStack(alignment: .leading, spacing: 2) {
                Text(poi.name)
                    .font(.system(.subheadline, design: .rounded))
                    .fontWeight(.medium)
                    .lineLimit(1)

                HStack(spacing: 8) {
                    Label(poi.rating.formatted(.number.precision(.fractionLength(1))), systemImage: "star.fill")
                        .font(.system(.caption2, design: .rounded))
                        .foregroundColor(.orange)

                    if let queueTime = poi.queueTime, queueTime > 0 {
                        Label("排队约\(queueTime)min", systemImage: "clock")
                            .font(.system(.caption2, design: .rounded))
                            .foregroundColor(.secondary)
                    }

                    if poi.avgPrice > 0 {
                        Text("¥\(Int(poi.avgPrice))/人")
                            .font(.system(.caption2, design: .rounded))
                            .foregroundColor(.secondary)
                    }
                }
            }

            Spacer()
        }
    }
}

