import React from 'react';
import {
  View,
  StyleSheet,
  ViewStyle,
} from 'react-native';

interface LiquidGlassCardProps {
  children: React.ReactNode;
  style?: ViewStyle;
  tint?: string;
  radius?: number;
}

const LiquidGlassCard: React.FC<LiquidGlassCardProps> = ({
  children,
  style,
  tint = '#8B5CF6',
  radius = 24,
}) => {
  return (
    <View style={[styles.container, { borderRadius: radius }, style]}>
      {/* 毛玻璃层 */}
      <View style={[styles.glass, { borderRadius: radius }]} />
      {/* 渐变叠加层 */}
      <View
        style={[
          styles.tintOverlay,
          { borderRadius: radius, backgroundColor: tint + '15' },
        ]}
      />
      {/* 边缘高光 */}
      <View
        style={[
          styles.highlight,
          { borderRadius: radius, borderColor: tint + '30' },
        ]}
      />
      {/* 内容 */}
      <View style={styles.content}>{children}</View>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    position: 'relative',
    overflow: 'hidden',
  },
  glass: {
    ...StyleSheet.absoluteFillObject,
    backgroundColor: 'rgba(255,255,255,0.12)',
    // @ts-ignore - RN 0.85+ 支持 backdropFilter
    backdropFilter: 'blur(20px)',
  },
  tintOverlay: {
    ...StyleSheet.absoluteFillObject,
    opacity: 0.5,
  },
  highlight: {
    ...StyleSheet.absoluteFillObject,
    borderWidth: 1,
    borderStyle: 'solid',
  },
  content: {
    position: 'relative',
    zIndex: 1,
    padding: 16,
  },
});

export default LiquidGlassCard;

import React from 'react';
import {
  View,
  TextInput,
  TouchableOpacity,
  Text,
  StyleSheet,
} from 'react-native';

interface InputBarProps {
  value: string;
  onChangeText: (text: string) => void;
  onSubmit: () => void;
  placeholder?: string;
}

const InputBar: React.FC<InputBarProps> = ({
  value,
  onChangeText,
  onSubmit,
  placeholder = '比如：想吃火锅再去看展，预算 300，不排队',
}) => {
  return (
    <View style={styles.container}>
      <TextInput
        style={styles.input}
        value={value}
        onChangeText={onChangeText}
        placeholder={placeholder}
        placeholderTextColor="rgba(128, 128, 128, 0.6)"
        returnKeyType="search"
        onSubmitEditing={onSubmit}
      />
      <TouchableOpacity style={styles.micButton} onPress={() => {}}>
        <Text style={styles.micIcon}>🎤</Text>
      </TouchableOpacity>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: 'rgba(255,255,255,0.12)',
    borderRadius: 28,
    paddingHorizontal: 16,
    paddingVertical: 4,
    borderWidth: 1,
    borderColor: 'rgba(255,255,255,0.2)',
  },
  input: {
    flex: 1,
    fontSize: 16,
    color: '#000',
    paddingVertical: 12,
    fontFamily: 'System',
  },
  micButton: {
    width: 36,
    height: 36,
    borderRadius: 18,
    backgroundColor: 'rgba(255,255,255,0.15)',
    justifyContent: 'center',
    alignItems: 'center',
    marginLeft: 8,
  },
  micIcon: {
    fontSize: 16,
  },
});

export default InputBar;

import React from 'react';
import { View, Text, TouchableOpacity, StyleSheet, ScrollView } from 'react-native';
import LiquidGlassCard from './LiquidGlassCard';
import type { Route, POI } from '../types';
import {
  optimizationGoalLabels,
  optimizationGoalColors,
  categoryIcons,
  transportModeIcons,
} from '../types';

interface RouteCardProps {
  route: Route;
  isSelected: boolean;
  onPress: () => void;
}

const RouteCard: React.FC<RouteCardProps> = ({ route, isSelected, onPress }) => {
  const goal = route.optimizationGoal as keyof typeof optimizationGoalLabels;
  const label = optimizationGoalLabels[goal] || goal;
  const color = optimizationGoalColors[goal] || '#8B5CF6';

  return (
    <TouchableOpacity onPress={onPress} activeOpacity={0.8}>
      <LiquidGlassCard
        style={[
          styles.card,
          isSelected && { borderColor: color, borderWidth: 2 },
        ]}
        tint={color}
        radius={24}
      >
        {/* 标签 */}
        <View style={[styles.tag, { backgroundColor: color }]}>
          <Text style={styles.tagText}>{label}</Text>
        </View>

        {/* POI 链 */}
        <View style={styles.poiChain}>
          {route.segments.map((seg, i) => (
            <React.Fragment key={seg.poi.id}>
              <View style={styles.poiNode}>
                <Text style={styles.poiIcon}>
                  {categoryIcons[seg.poi.category] || '📍'}
                </Text>
                <Text style={styles.poiName} numberOfLines={1}>
                  {seg.poi.name}
                </Text>
              </View>
              {i < route.segments.length - 1 && (
                <Text style={styles.arrow}>→</Text>
              )}
            </React.Fragment>
          ))}
        </View>

        {/* 概览信息 */}
        <View style={styles.meta}>
          <View style={styles.metaItem}>
            <Text style={styles.metaIcon}>⏱️</Text>
            <Text style={styles.metaText}>
              {Math.round(route.totalTravelTime)}分钟
            </Text>
          </View>
          <View style={styles.metaItem}>
            <Text style={styles.metaIcon}>💰</Text>
            <Text style={styles.metaText}>¥{route.totalCost}</Text>
          </View>
          <View style={styles.metaItem}>
            <Text style={styles.metaIcon}>⭐</Text>
            <Text style={styles.metaText}>{route.totalRating.toFixed(1)}</Text>
          </View>
        </View>

        {/* POI 详情 */}
        {isSelected && (
          <View style={styles.poiDetails}>
            {route.segments.map((seg, i) => (
              <View key={seg.poi.id} style={styles.poiDetailRow}>
                <View style={styles.poiDetailHeader}>
                  <Text style={styles.poiDetailIcon}>
                    {categoryIcons[seg.poi.category] || '📍'}
                  </Text>
                  <Text style={styles.poiDetailName}>{seg.poi.name}</Text>
                  <Text style={styles.poiDetailRating}>
                    ⭐ {seg.poi.rating.toFixed(1)}
                  </Text>
                </View>
                <View style={styles.poiDetailInfo}>
                  {seg.poi.queueTime > 0 && (
                    <Text style={styles.poiDetailSub}>
                      排队约{seg.poi.queueTime}分钟
                    </Text>
                  )}
                  <Text style={styles.poiDetailSub}>
                    ¥{seg.poi.avgCost}/人 · ⏱{seg.poi.visitDuration}分钟
                  </Text>
                </View>
                {seg.travelTimeFromPrevious > 0 && (
                  <View style={styles.transportRow}>
                    <Text style={styles.transportIcon}>
                      {transportModeIcons[seg.travelMode] || '🚶'}
                    </Text>
                    <Text style={styles.transportText}>
                      {seg.travelMode === 'WALKING' ? '步行' : '驾车'}{' '}
                      {seg.travelTimeFromPrevious}分钟
                    </Text>
                  </View>
                )}
              </View>
            ))}
          </View>
        )}
      </LiquidGlassCard>
    </TouchableOpacity>
  );
};

const styles = StyleSheet.create({
  card: {
    width: 320,
    marginRight: 16,
