import React, { useState, useRef } from 'react';
import {
  View,
  Text,
  ScrollView,
  TouchableOpacity,
  TextInput,
  StyleSheet,
  SafeAreaView,
  StatusBar,
  FlatList,
  Dimensions,
  Alert,
} from 'react-native';
import RouteCard from '../components/RouteCard';
import Timeline from '../components/Timeline';
import { mockData, routeApi } from '../services/api';
import type { Route } from '../types';

const { width: SCREEN_WIDTH } = Dimensions.get('window');

interface RouteResultScreenProps {
  plans: Route[];
  sessionId: string;
  explanation: string;
  onBack: () => void;
}

const RouteResultScreen: React.FC<RouteResultScreenProps> = ({
  plans,
  sessionId,
  explanation,
  onBack,
}) => {
  const [allPlans, setAllPlans] = useState(plans);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [adjustmentText, setAdjustmentText] = useState('');
  const [showTimeline, setShowTimeline] = useState(false);
  const [adjusting, setAdjusting] = useState(false);
  const [useMock] = useState(true);
  const flatListRef = useRef<FlatList>(null);

  const currentPlan = allPlans[selectedIndex];

  // 撤销/重做栈
  const [undoStack, setUndoStack] = useState<Route[][]>([]);
  const [redoStack, setRedoStack] = useState<Route[][]>([]);

  const handleAdjust = async () => {
    if (!adjustmentText.trim()) return;

    setUndoStack(prev => [...prev, allPlans]);
    setRedoStack([]);
    setAdjusting(true);

    try {
      let result;
      if (useMock) {
        result = await mockData.adjustRoute(sessionId, adjustmentText);
      } else {
        result = await routeApi.adjustRoute(sessionId, adjustmentText);
      }

      if (result.routes.length > 0) {
        setAllPlans(result.routes);
        setSelectedIndex(0);
      }
      setAdjustmentText('');
    } catch (err: any) {
      Alert.alert('调整失败', err?.message || '请稍后重试');
    } finally {
      setAdjusting(false);
    }
  };

  const handleUndo = () => {
    const prev = undoStack[undoStack.length - 1];
    if (!prev) return;
    setUndoStack(prev => prev.slice(0, -1));
    setRedoStack(prev => [...prev, allPlans]);
    setAllPlans(prev);
  };

  const handleRedo = () => {
    const next = redoStack[redoStack.length - 1];
    if (!next) return;
    setRedoStack(prev => prev.slice(0, -1));
    setUndoStack(prev => [...prev, allPlans]);
    setAllPlans(next);
  };

  const handleCardSelect = (index: number) => {
    setSelectedIndex(index);
    flatListRef.current?.scrollToIndex({ index, animated: true });
  };

  if (showTimeline && currentPlan) {
    return (
      <SafeAreaView style={styles.container}>
        <StatusBar barStyle="dark-content" />
        <View style={styles.timelineHeader}>
          <TouchableOpacity onPress={() => setShowTimeline(false)}>
            <Text style={styles.backButton}>← 返回</Text>
          </TouchableOpacity>
          <Text style={styles.timelineTitle}>详细日程</Text>
          <View style={{ width: 60 }} />
        </View>
        <Timeline route={currentPlan} />
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <StatusBar barStyle="dark-content" />

      {/* 顶栏 */}
      <View style={styles.topBar}>
        <TouchableOpacity onPress={onBack}>
          <Text style={styles.backButton}>← 返回</Text>
        </TouchableOpacity>
        <Text style={styles.title}>路线方案</Text>
        <View style={styles.undoRow}>
          <TouchableOpacity
            onPress={handleUndo}
            disabled={undoStack.length === 0}
          >
            <Text
              style={[
                styles.undoText,
                undoStack.length === 0 && styles.disabled,
              ]}
            >
              ↩
            </Text>
          </TouchableOpacity>
          <TouchableOpacity
            onPress={handleRedo}
            disabled={redoStack.length === 0}
          >
            <Text
              style={[
                styles.undoText,
                redoStack.length === 0 && styles.disabled,
              ]}
            >
              ↪
            </Text>
          </TouchableOpacity>
        </View>
      </View>

      {/* 方案选择标签 */}
      <ScrollView
        horizontal
        showsHorizontalScrollIndicator={false}
        style={styles.tagScroll}
        contentContainerStyle={styles.tagContainer}
      >
        {allPlans.map((plan, index) => (
          <TouchableOpacity
            key={plan.id}
            style={[
              styles.tag,
              selectedIndex === index && styles.tagActive,
            ]}
            onPress={() => handleCardSelect(index)}
          >
            <View
              style={[
                styles.tagDot,
                {
                  backgroundColor:
                    selectedIndex === index ? '#8B5CF6' : '#ccc',
                },
              ]}
            />
            <Text
              style={[
                styles.tagLabel,
                selectedIndex === index && styles.tagLabelActive,
              ]}
            >
              {plan.optimizationGoal === 'BEST_EXPERIENCE'
                ? '体验优先'
                : plan.optimizationGoal === 'FASTEST'
                ? '最省时'
                : '最省钱'}
            </Text>
          </TouchableOpacity>
        ))}
      </ScrollView>

      {/* 卡片流 */}
      <View style={styles.cardContainer}>
        <FlatList
          ref={flatListRef}
          data={allPlans}
          horizontal
          showsHorizontalScrollIndicator={false}
          snapToInterval={336}
          decelerationRate="fast"
          onMomentumScrollEnd={e => {
            const index = Math.round(
              e.nativeEvent.contentOffset.x / 336
            );
            if (index !== selectedIndex) {
              setSelectedIndex(index);
            }
          }}
          renderItem={({ item, index }) => (
            <View style={styles.cardWrapper}>
              <RouteCard
                route={item}
                isSelected={index === selectedIndex}
                onPress={() => {
                  setSelectedIndex(index);
                  setShowTimeline(true);
                }}
              />
            </View>
          )}
          keyExtractor={item => item.id}
        />
      </View>

      {/* 推荐理由 */}
      {currentPlan && (
        <View style={styles.explanation}>
          <Text style={styles.explanationText}>{currentPlan.description}</Text>
        </View>
      )}

      {/* 调整输入 */}
      <View style={styles.adjustmentRow}>
        <View style={styles.adjustmentInputContainer}>
          <TextInput
            style={styles.adjustmentInput}
            value={adjustmentText}
            onChangeText={setAdjustmentText}
            placeholder="换一家不用排队的咖啡店"
            placeholderTextColor="rgba(128,128,128,0.6)"
            returnKeyType="send"
            onSubmitEditing={handleAdjust}
          />
        </View>
        <TouchableOpacity
          style={[
            styles.adjustButton,
            !adjustmentText.trim() && styles.adjustButtonDisabled,
          ]}
          onPress={handleAdjust}
          disabled={!adjustmentText.trim() || adjusting}
        >
          <Text style={styles.adjustButtonText}>
            {adjusting ? '...' : '调整'}
          </Text>
        </TouchableOpacity>
      </View>

      {/* 底部操作栏 */}
      <View style={styles.bottomBar}>
        <TouchableOpacity
          style={styles.secondaryButton}
          onPress={() => setShowTimeline(true)}
        >
          <Text style={styles.secondaryButtonText}>📋 详细日程</Text>
        </TouchableOpacity>
        <TouchableOpacity style={styles.primaryButton}>
          <Text style={styles.primaryButtonText}>📍 开始导航</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F5F5F7',
  },
  topBar: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingHorizontal: 20,
    paddingVertical: 12,
    backgroundColor: 'rgba(255,255,255,0.8)',
    borderBottomWidth: StyleSheet.hairlineWidth,
    borderBottomColor: 'rgba(0,0,0,0.05)',
  },
  backButton: {
    fontSize: 17,
    color: '#8B5CF6',
    fontWeight: '500',
  },
  title: {
    fontSize: 17,
    fontWeight: '600',
    color: '#1a1a1a',
  },
  undoRow: {
    flexDirection: 'row',
    gap: 12,
  },
  undoText: {
    fontSize: 18,
